import type {
  AdapterCapabilities,
  AdapterCategory,
  AdapterSubscription,
  ConnectionStatus,
  ExchangeAdapter,
  ExchangeConfig,
  HealthMetrics,
  OHLCVCallback,
  OrderbookCallback,
  StatusCallback,
  TickerCallback,
  TradeCallback,
} from '../../types/adapter';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedSymbol, NormalizedTrade, Timeframe } from '../../types/normalized';
import { createSubscriptionId, splitConcatenatedSymbol, parseNumeric } from '../../normalization/pipeline';
import { RateLimiter, EXCHANGE_RATE_LIMITS } from '../../rate-limiter/rate-limiter';
import { BinanceNormalizer } from './binance-normalizer';
import type { BinanceExchangeInfoSymbol, BinanceRestKline, BinanceRawMessage } from './binance-types';

import { CircuitBreaker } from '../../circuit-breaker/circuit-breaker';

const DEFAULT_WS_URL = 'wss://stream.binance.us:9443/stream';
const DEFAULT_REST_URL = 'https://api.binance.us';
const TESTNET_WS_URL = 'wss://testnet.binance.vision/ws';
const TESTNET_REST_URL = 'https://testnet.binance.vision';

/** Maximum WebSocket connection duration before proactive reconnect (23 hours in ms). */
const PROACTIVE_RECONNECT_MS = 23 * 60 * 60 * 1000;

/** Maximum number of streams per combined connection. */
const MAX_STREAMS_PER_CONNECTION = 1024;

/** Default heartbeat timeout for Binance (60 seconds). */
const DEFAULT_HEARTBEAT_TIMEOUT_MS = 60_000;

/** Timeframe to Binance interval mapping. */
const TIMEFRAME_MAP: Readonly<Record<Timeframe, string>> = {
  '1s': '1s', '5s': '5s', '15s': '15s', '30s': '30s',
  '1m': '1m', '3m': '3m', '5m': '5m', '15m': '15m', '30m': '30m',
  '1h': '1h', '2h': '2h', '4h': '4h', '6h': '6h', '8h': '8h', '12h': '12h',
  '1d': '1d', '3d': '3d', '1w': '1w', '1M': '1M',
};

interface ActiveSubscription {
  readonly id: string;
  readonly symbol: string;
  readonly streamName: string;
  readonly type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv' | 'status';
  readonly callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback | StatusCallback;
}

/**
 * Binance exchange adapter. Connects to the combined WebSocket stream
 * and multiplexes all subscriptions over a single connection.
 *
 * Features:
 * - Combined stream multiplexing (up to 1024 streams)
 * - Proactive reconnection at 23 hours (24h limit)
 * - Rate-limited REST API calls
 * - Exponential backoff reconnection with jitter
 */
export class BinanceAdapter implements ExchangeAdapter {
  readonly exchangeId = 'binance' as const;
  readonly displayName = 'Binance';
  readonly category: AdapterCategory = 'cex';
  readonly capabilities: AdapterCapabilities = {
    realtime: true,
    historicalDepth: '7y',
    orderbook: true,
    trades: true,
    ohlcv: true,
    fundingRates: false,
    openInterest: false,
    liquidations: false,
    defiMetrics: false,
    onChainMetrics: false,
    authenticated: true,
  };

  private ws: WebSocket | null = null;
  private config: ExchangeConfig | null = null;
  private readonly normalizer = new BinanceNormalizer();
  private rateLimiter: RateLimiter | null = null;
  private readonly subscriptions = new Map<string, ActiveSubscription>();
  private readonly statusCallbacks = new Map<string, StatusCallback>();
  private connectionState: ConnectionStatus = {
    state: 'disconnected',
    latencyMs: 0,
    messagesPerSecond: 0,
    lastMessageAt: 0,
    reconnectAttempt: 0,
    uptime: 0,
  };
  private connectTime = 0;
  private reconnectAttempt = 0;
  private reconnectTimer: ReturnType<typeof setTimeout> | undefined;
  private proactiveReconnectTimer: ReturnType<typeof setTimeout> | undefined;
  private messageCount = 0;
  private messageRateWindowStart = 0;
  private readonly circuitBreaker = new CircuitBreaker();
  private heartbeatTimer: ReturnType<typeof setTimeout> | undefined;
  private heartbeatTimeoutMs = DEFAULT_HEARTBEAT_TIMEOUT_MS;
  private totalErrors = 0;
  private totalRequests = 0;

  async connect(config: ExchangeConfig): Promise<void> {
    this.config = config;
    this.heartbeatTimeoutMs = config.heartbeatTimeoutMs ?? DEFAULT_HEARTBEAT_TIMEOUT_MS;
    if (config.circuitBreaker) {
      this.circuitBreaker.reset();
    }
    const rateLimitConfig = EXCHANGE_RATE_LIMITS['binance'];
    if (rateLimitConfig) {
      this.rateLimiter = new RateLimiter('binance', rateLimitConfig);
    }
    await this.circuitBreaker.execute(() => this.establishConnection());
  }

  async disconnect(): Promise<void> {
    this.clearTimers();
    this.stopHeartbeat();
    if (this.ws) {
      this.ws.onclose = null;
      this.ws.onerror = null;
      this.ws.onmessage = null;
      this.ws.close();
      this.ws = null;
    }
    this.subscriptions.clear();
    this.statusCallbacks.clear();
    this.rateLimiter?.dispose();
    this.rateLimiter = null;
    this.circuitBreaker.reset();
    this.updateState('disconnected');
  }

  getStatus(): ConnectionStatus {
    return { ...this.connectionState, uptime: this.getUptime() };
  }

  getHealthMetrics(): HealthMetrics {
    const status = this.getStatus();
    const uptimeSeconds = status.uptime;
    const uptimePercent = uptimeSeconds > 0
      ? Math.min(100, (uptimeSeconds / (uptimeSeconds + this.reconnectAttempt * 5)) * 100)
      : 0;
    return {
      connected: status.state === 'connected',
      latencyMs: status.latencyMs,
      messagesPerSecond: status.messagesPerSecond,
      uptimePercent,
      lastMessageAt: status.lastMessageAt,
      errorRate: this.totalRequests > 0 ? this.totalErrors / this.totalRequests : 0,
      circuitBreakerState: this.circuitBreaker.state,
    };
  }

  onStatusChange(callback: StatusCallback): AdapterSubscription {
    const id = createSubscriptionId('binance', 'status', '_global');
    this.statusCallbacks.set(id, callback);
    return {
      id,
      symbol: '_global',
      type: 'status',
      dispose: () => { this.statusCallbacks.delete(id); },
    };
  }

  subscribeTicker(symbol: string, callback: TickerCallback): AdapterSubscription {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const streamName = `${exchangeSymbol.toLowerCase()}@miniTicker`;
    return this.addSubscription(symbol, streamName, 'ticker', callback);
  }

  subscribeOrderbook(symbol: string, depth: number, callback: OrderbookCallback): AdapterSubscription {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const depthLevel = depth <= 5 ? 5 : depth <= 10 ? 10 : 20;
    const streamName = `${exchangeSymbol.toLowerCase()}@depth${depthLevel}@100ms`;
    return this.addSubscription(symbol, streamName, 'orderbook', callback);
  }

  subscribeTrades(symbol: string, callback: TradeCallback): AdapterSubscription {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const streamName = `${exchangeSymbol.toLowerCase()}@trade`;
    return this.addSubscription(symbol, streamName, 'trades', callback);
  }

  subscribeOHLCV(symbol: string, timeframe: Timeframe, callback: OHLCVCallback): AdapterSubscription {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const interval = TIMEFRAME_MAP[timeframe];
    const streamName = `${exchangeSymbol.toLowerCase()}@kline_${interval}`;
    return this.addSubscription(symbol, streamName, 'ohlcv', callback);
  }

  async getCandles(symbol: string, timeframe: Timeframe, from: number, to: number): Promise<NormalizedOHLCV[]> {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const interval = TIMEFRAME_MAP[timeframe];
    const url = `${this.getRestUrl()}/api/v3/klines?symbol=${exchangeSymbol}&interval=${interval}&startTime=${from}&endTime=${to}&limit=1000`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Binance REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as BinanceRestKline[];
    return data.map(kline => this.normalizer.normalizeRestKline(kline));
  }

  async getOrderbookSnapshot(symbol: string, depth: number): Promise<NormalizedOrderbook> {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const limit = Math.min(depth, 1000);
    const url = `${this.getRestUrl()}/api/v3/depth?symbol=${exchangeSymbol}&limit=${limit}`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Binance REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as {
      lastUpdateId: number;
      bids: [string, string][];
      asks: [string, string][];
    };

    const normalizedSymbol = splitConcatenatedSymbol(exchangeSymbol);
    return {
      symbol: normalizedSymbol,
      timestamp: Date.now(),
      bids: data.bids.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      asks: data.asks.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      sequenceId: data.lastUpdateId,
      type: 'snapshot',
    };
  }

  async getRecentTrades(symbol: string, limit: number): Promise<NormalizedTrade[]> {
    const exchangeSymbol = this.toExchangeSymbol(symbol);
    const url = `${this.getRestUrl()}/api/v3/trades?symbol=${exchangeSymbol}&limit=${Math.min(limit, 1000)}`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Binance REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as Array<{
      id: number;
      price: string;
      qty: string;
      time: number;
      isBuyerMaker: boolean;
    }>;

    return data.map(trade => ({
      id: String(trade.id),
      timestamp: trade.time,
      price: parseNumeric(trade.price),
      quantity: parseNumeric(trade.qty),
      side: trade.isBuyerMaker ? 'sell' as const : 'buy' as const,
      buyerMaker: trade.isBuyerMaker,
    }));
  }

  async getSymbols(): Promise<NormalizedSymbol[]> {
    const url = `${this.getRestUrl()}/api/v3/exchangeInfo`;

    await this.rateLimiter?.acquire();
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Binance REST error: ${response.status} ${response.statusText}`);
    }
    const data = await response.json() as { symbols: BinanceExchangeInfoSymbol[] };

    return data.symbols
      .filter(s => s.status === 'TRADING')
      .map(s => this.normalizeSymbolInfo(s));
  }

  private normalizeSymbolInfo(raw: BinanceExchangeInfoSymbol): NormalizedSymbol {
    const lotSize = raw.filters.find(f => f.filterType === 'LOT_SIZE');
    const priceFilter = raw.filters.find(f => f.filterType === 'PRICE_FILTER');

    return {
      symbol: `${raw.baseAsset}/${raw.quoteAsset}`,
      base: raw.baseAsset,
      quote: raw.quoteAsset,
      exchangeSymbol: raw.symbol,
      exchangeId: 'binance',
      type: 'spot',
      pricePrecision: raw.quotePrecision,
      quantityPrecision: raw.baseAssetPrecision,
      minQuantity: parseNumeric(lotSize?.minQty),
      tickSize: parseNumeric(priceFilter?.tickSize),
      active: raw.status === 'TRADING',
    };
  }

  private addSubscription(
    symbol: string,
    streamName: string,
    type: 'ticker' | 'orderbook' | 'trades' | 'ohlcv',
    callback: TickerCallback | OrderbookCallback | TradeCallback | OHLCVCallback,
  ): AdapterSubscription {
    const id = createSubscriptionId('binance', type, symbol);
    const sub: ActiveSubscription = { id, symbol, streamName, type, callback };
    this.subscriptions.set(id, sub);

    if (this.ws?.readyState === WebSocket.OPEN) {
      this.sendSubscribe([streamName]);
    }

    return {
      id,
      symbol,
      type,
      dispose: () => {
        this.subscriptions.delete(id);
        const stillUsed = Array.from(this.subscriptions.values()).some(s => s.streamName === streamName);
        if (!stillUsed && this.ws?.readyState === WebSocket.OPEN) {
          this.sendUnsubscribe([streamName]);
        }
      },
    };
  }

  private async establishConnection(): Promise<void> {
    this.updateState('connecting');
    const wsUrl = this.getWsUrl();

    return new Promise<void>((resolve, reject) => {
      try {
        this.ws = new WebSocket(wsUrl);
      } catch (err) {
        this.updateState('error', err instanceof Error ? err.message : 'WebSocket creation failed');
        reject(err);
        return;
      }

      this.ws.onopen = () => {
        this.connectTime = Date.now();
        this.reconnectAttempt = 0;
        this.messageRateWindowStart = Date.now();
        this.messageCount = 0;
        this.updateState('connected');
        this.startHeartbeat();

        // Resubscribe to all active streams
        const streams = this.getActiveStreamNames();
        if (streams.length > 0) {
          this.sendSubscribe(streams);
        }

        // Schedule proactive reconnect at 23 hours
        this.proactiveReconnectTimer = setTimeout(() => {
          this.reconnect();
        }, PROACTIVE_RECONNECT_MS);

        resolve();
      };

      this.ws.onmessage = (event: MessageEvent) => {
        this.handleMessage(event.data as string);
      };

      this.ws.onerror = () => {
        this.updateState('error', 'WebSocket error');
      };

      this.ws.onclose = () => {
        if (this.connectionState.state !== 'disconnected') {
          this.reconnect();
        }
      };
    });
  }

  private handleMessage(rawData: string): void {
    this.messageCount++;
    this.resetHeartbeat();
    const now = Date.now();
    const elapsed = now - this.messageRateWindowStart;
    if (elapsed >= 10_000) {
      this.connectionState = {
        ...this.connectionState,
        messagesPerSecond: this.messageCount / (elapsed / 1000),
        lastMessageAt: now,
      };
      this.messageCount = 0;
      this.messageRateWindowStart = now;
    }

    const message = this.normalizer.parseMessage(rawData);
    if (!message) return;

    // Route to matching subscriptions
    for (const sub of this.subscriptions.values()) {
      switch (sub.type) {
        case 'ticker': {
          const tick = this.normalizer.normalizeTicker(message);
          if (tick) (sub.callback as TickerCallback)(tick);
          break;
        }
        case 'trades': {
          const trade = this.normalizer.normalizeTrade(message);
          if (trade) (sub.callback as TradeCallback)(trade);
          break;
        }
        case 'ohlcv': {
          const candle = this.normalizer.normalizeOHLCV(message);
          if (candle) (sub.callback as OHLCVCallback)(candle);
          break;
        }
        case 'orderbook': {
          const book = this.normalizer.normalizeOrderbook(message);
          if (book) (sub.callback as OrderbookCallback)(book);
          break;
        }
      }
    }
  }

  private reconnect(): void {
    if (this.connectionState.state === 'disconnected') return;
    this.clearTimers();
    this.stopHeartbeat();
    this.circuitBreaker.recordFailure();

    if (this.ws) {
      this.ws.onclose = null;
      this.ws.onerror = null;
      this.ws.onmessage = null;
      this.ws.close();
      this.ws = null;
    }

    this.reconnectAttempt++;
    this.totalErrors++;
    this.updateState('reconnecting');

    const baseDelay = Math.min(1000 * Math.pow(2, this.reconnectAttempt - 1), 16_000);
    const jitter = Math.random() * baseDelay * 0.25;
    const delay = this.reconnectAttempt === 1 ? 0 : baseDelay + jitter;

    this.reconnectTimer = setTimeout(() => {
      this.circuitBreaker.execute(() => this.establishConnection()).catch(() => {
        this.reconnect();
      });
    }, delay);
  }

  private sendSubscribe(streams: string[]): void {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) return;
    if (streams.length === 0) return;
    this.ws.send(JSON.stringify({
      method: 'SUBSCRIBE',
      params: streams.slice(0, MAX_STREAMS_PER_CONNECTION),
      id: Date.now(),
    }));
  }

  private sendUnsubscribe(streams: string[]): void {
    if (!this.ws || this.ws.readyState !== WebSocket.OPEN) return;
    if (streams.length === 0) return;
    this.ws.send(JSON.stringify({
      method: 'UNSUBSCRIBE',
      params: streams,
      id: Date.now(),
    }));
  }

  private getActiveStreamNames(): string[] {
    const streams = new Set<string>();
    for (const sub of this.subscriptions.values()) {
      streams.add(sub.streamName);
    }
    return Array.from(streams);
  }

  private updateState(state: ConnectionStatus['state'], errorMessage?: string): void {
    this.connectionState = {
      state,
      latencyMs: this.connectionState.latencyMs,
      messagesPerSecond: this.connectionState.messagesPerSecond,
      lastMessageAt: this.connectionState.lastMessageAt,
      errorMessage,
      reconnectAttempt: this.reconnectAttempt,
      uptime: this.getUptime(),
    };
    for (const callback of this.statusCallbacks.values()) {
      callback(this.connectionState);
    }
  }

  private getUptime(): number {
    if (this.connectTime === 0) return 0;
    return (Date.now() - this.connectTime) / 1000;
  }

  private getWsUrl(): string {
    if (this.config?.wsUrl) return this.config.wsUrl;
    return this.config?.testnet ? TESTNET_WS_URL : DEFAULT_WS_URL;
  }

  private getRestUrl(): string {
    if (this.config?.restUrl) return this.config.restUrl;
    return this.config?.testnet ? TESTNET_REST_URL : DEFAULT_REST_URL;
  }

  private toExchangeSymbol(symbol: string): string {
    // Convert "BTC/USDT" to "BTCUSDT"
    return symbol.replace('/', '');
  }

  private startHeartbeat(): void {
    this.stopHeartbeat();
    this.heartbeatTimer = setTimeout(() => {
      this.onHeartbeatTimeout();
    }, this.heartbeatTimeoutMs);
  }

  private resetHeartbeat(): void {
    if (this.heartbeatTimer !== undefined) {
      clearTimeout(this.heartbeatTimer);
      this.heartbeatTimer = setTimeout(() => {
        this.onHeartbeatTimeout();
      }, this.heartbeatTimeoutMs);
    }
  }

  private stopHeartbeat(): void {
    if (this.heartbeatTimer !== undefined) {
      clearTimeout(this.heartbeatTimer);
      this.heartbeatTimer = undefined;
    }
  }

  private onHeartbeatTimeout(): void {
    this.updateState('error', 'Heartbeat timeout');
    this.reconnect();
  }

  private clearTimers(): void {
    if (this.reconnectTimer !== undefined) {
      clearTimeout(this.reconnectTimer);
      this.reconnectTimer = undefined;
    }
    if (this.proactiveReconnectTimer !== undefined) {
      clearTimeout(this.proactiveReconnectTimer);
      this.proactiveReconnectTimer = undefined;
    }
  }
}
