import type { MessageNormalizer } from '../../normalization/pipeline';
import { parseNumeric, splitConcatenatedSymbol } from '../../normalization/pipeline';
import type { NormalizedOHLCV, NormalizedOrderbook, NormalizedTick, NormalizedTrade } from '../../types/normalized';
import type {
  BinanceCombinedStream,
  BinanceDepthMessage,
  BinanceKlineMessage,
  BinanceMiniTickerMessage,
  BinanceRawMessage,
  BinanceRestKline,
  BinanceTradeMessage,
} from './binance-types';

/**
 * Normalizes raw Binance WebSocket and REST messages into Deskmodal
 * normalized data types.
 *
 * Handles:
 * - Combined stream unwrapping (stream envelope -> data payload)
 * - Numeric strings -> JavaScript numbers
 * - BTCUSDT -> BTC/USDT symbol normalization
 * - Kline, trade, mini ticker, and depth message types
 */
export class BinanceNormalizer implements MessageNormalizer<BinanceRawMessage> {
  parseMessage(raw: string): BinanceRawMessage | undefined {
    try {
      const parsed: unknown = JSON.parse(raw);
      if (typeof parsed !== 'object' || parsed === null) return undefined;

      // Combined stream messages are wrapped in { stream, data }
      if ('stream' in parsed && 'data' in parsed) {
        const combined = parsed as BinanceCombinedStream;
        return combined.data;
      }

      // Single stream messages have event type at top level
      if ('e' in parsed) {
        return parsed as BinanceRawMessage;
      }

      return undefined;
    } catch {
      return undefined;
    }
  }

  normalizeTicker(raw: BinanceRawMessage): NormalizedTick | undefined {
    if (raw.e !== '24hrMiniTicker') return undefined;
    const msg = raw as BinanceMiniTickerMessage;
    const symbol = splitConcatenatedSymbol(msg.s);
    const closePrice = parseNumeric(msg.c);
    const openPrice = parseNumeric(msg.o);
    const priceChange = closePrice - openPrice;
    const priceChangePercent = openPrice !== 0 ? (priceChange / openPrice) * 100 : 0;

    return {
      symbol,
      lastPrice: closePrice,
      priceChange,
      priceChangePercent,
      high24h: parseNumeric(msg.h),
      low24h: parseNumeric(msg.l),
      volume24h: parseNumeric(msg.v),
      quoteVolume24h: parseNumeric(msg.q),
      timestamp: msg.E,
      bestBid: 0,
      bestBidQty: 0,
      bestAsk: 0,
      bestAskQty: 0,
    };
  }

  normalizeTrade(raw: BinanceRawMessage): NormalizedTrade | undefined {
    if (raw.e !== 'trade') return undefined;
    const msg = raw as BinanceTradeMessage;

    return {
      id: String(msg.t),
      timestamp: msg.T,
      price: parseNumeric(msg.p),
      quantity: parseNumeric(msg.q),
      side: msg.m ? 'sell' : 'buy',
      buyerMaker: msg.m,
    };
  }

  normalizeOHLCV(raw: BinanceRawMessage): NormalizedOHLCV | undefined {
    if (raw.e !== 'kline') return undefined;
    const msg = raw as BinanceKlineMessage;
    const k = msg.k;

    return {
      timestamp: k.t,
      open: parseNumeric(k.o),
      high: parseNumeric(k.h),
      low: parseNumeric(k.l),
      close: parseNumeric(k.c),
      volume: parseNumeric(k.v),
      quoteVolume: parseNumeric(k.q),
      tradeCount: k.n,
      closed: k.x,
    };
  }

  normalizeOrderbook(raw: BinanceRawMessage): NormalizedOrderbook | undefined {
    if (raw.e !== 'depthUpdate') return undefined;
    const msg = raw as BinanceDepthMessage;
    const symbol = splitConcatenatedSymbol(msg.s);

    return {
      symbol,
      timestamp: msg.E,
      bids: msg.b.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      asks: msg.a.map(([price, qty]) => ({
        price: parseNumeric(price),
        quantity: parseNumeric(qty),
      })),
      sequenceId: msg.u,
      type: 'delta',
    };
  }

  /** Normalize a REST API kline (positional array) into NormalizedOHLCV. */
  normalizeRestKline(kline: BinanceRestKline): NormalizedOHLCV {
    return {
      timestamp: kline[0],
      open: parseNumeric(kline[1]),
      high: parseNumeric(kline[2]),
      low: parseNumeric(kline[3]),
      close: parseNumeric(kline[4]),
      volume: parseNumeric(kline[5]),
      quoteVolume: parseNumeric(kline[7]),
      tradeCount: kline[8],
      closed: true,
    };
  }
}
